// src/pages/Order.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "../styles/style.css";

export default function Order() {
  const [menu, setMenu] = useState([]);
  const [form, setForm] = useState({
    fullName: "",
    phoneNumber: "",
    notes: "",
  });
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const navigate = useNavigate();

  /* ---------------------------------------------
     Fetch Menu
  ------------------------------------------------*/
  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const url = process.env.REACT_APP_API_URL
          ? `${process.env.REACT_APP_API_URL}/api/items`
          : "http://localhost:5000/api/items";

        const res = await axios.get(url);

        // Group items by category
        const grouped = res.data.reduce((acc, item) => {
          const category = item.category || "Others";
          if (!acc[category]) acc[category] = [];
          acc[category].push(item);
          return acc;
        }, {});

        // Convert object → array (clean)
        const finalMenu = Object.entries(grouped).map(([category, items], i) => ({
          id: i,
          category,
          items,
        }));

        setMenu(finalMenu);
      } catch (err) {
        setError("Failed to load menu items.");
      } finally {
        setLoading(false);
      }
    };

    fetchMenu();
  }, []);

  /* ---------------------------------------------
     Handle quantity
  ------------------------------------------------*/
  const handleQty = (id, qty) => {
    setQuantities((prev) => ({
      ...prev,
      [id]: Math.max(0, parseInt(qty) || 0),
    }));
  };

  /* ---------------------------------------------
     Handle text inputs (name - phone - notes)
  ------------------------------------------------*/
  const handleInput = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  /* ---------------------------------------------
     Submit order
  ------------------------------------------------*/
  const submitOrder = async (e) => {
    e.preventDefault();

    const selectedItems = [];

    menu.forEach((section) =>
      section.items.forEach((item) => {
        const qty = quantities[item.item_id] || 0;
        if (qty > 0) {
          selectedItems.push({
            item_id: item.item_id,
            item_name: item.item_name,
            qty,
            price: parseFloat(item.price),
          });
        }
      })
    );

    if (selectedItems.length === 0)
      return alert("Please select at least one item.");

    const order = {
      ...form,
      items: selectedItems,
      date: new Date().toISOString(),
      orderId: Date.now(),
    };

    try {
      // Save locally
      const old = JSON.parse(localStorage.getItem("orders")) || [];
      localStorage.setItem("orders", JSON.stringify([...old, order]));

      // Save to backend
      const url = process.env.REACT_APP_API_URL
        ? `${process.env.REACT_APP_API_URL}/api/orders`
        : "http://localhost:5000/api/orders";

      await axios.post(url, order);

      navigate("/order-confirmation", { state: order });

      // Reset
      setForm({ fullName: "", phoneNumber: "", notes: "" });
      setQuantities({});
    } catch (err) {
      alert("Failed to submit order.");
    }
  };

  /* ---------------------------------------------
     UI Rendering
  ------------------------------------------------*/
  return (
    <div className="order-page">
      <div className="order-container">

        <button className="back-btn" onClick={() => navigate("/home")}>
          ← Back to Home
        </button>

        <h2 className="order-title">Place Your Order</h2>
        <p className="order-subtitle">
          Choose your items and complete your order
        </p>

        {loading && <p className="loading">Loading menu...</p>}
        {error && <p className="error">{error}</p>}

        {!loading && !error && (
          <form onSubmit={submitOrder} className="order-form">

            {/* ---------------- FORM INPUTS ---------------- */}
            <div className="input-group">
              <label>Full Name</label>
              <input
                name="fullName"
                value={form.fullName}
                onChange={handleInput}
                placeholder="Enter your full name"
                required
              />
            </div>

            <div className="input-group">
              <label>Phone Number</label>
              <input
                name="phoneNumber"
                value={form.phoneNumber}
                onChange={handleInput}
                placeholder="Enter your phone number"
                required
              />
            </div>

            {/* ---------------- MENU SECTIONS ---------------- */}
            {menu.map((section) => (
              <div key={section.id} className="menu-section">
                <h3 className="section-title">{section.category}</h3>

                <div className="menu-grid">
                  {section.items.map((item) => (
                    <div key={item.item_id} className="menu-card">
                      <div className="item-header">
                        <h4>{item.item_name}</h4>
                        <span className="price">${parseFloat(item.price).toFixed(2)}</span>
                      </div>

                      <input
                        type="number"
                        min="0"
                        className="qty-input"
                        value={quantities[item.item_id] || 0}
                        onChange={(e) =>
                          handleQty(item.item_id, e.target.value)
                        }
                      />
                    </div>
                  ))}
                </div>
              </div>
            ))}

            {/* ---------------- NOTES ---------------- */}
            <div className="input-group">
              <label>Additional Notes</label>
              <textarea
                name="notes"
                value={form.notes}
                onChange={handleInput}
                placeholder="Any special instructions?"
                rows="3"
              />
            </div>

            {/* ---------------- SUBMIT BTN ---------------- */}
            <button type="submit" className="submit-btn">
              Submit Order
            </button>
          </form>
        )}
      </div>
    </div>
  );
}
